'use client'

import { useEffect } from 'react'

const IMG_WORDMARK =
  'data:image/png;base64,'

const IMG_TOP =
  'data:image/png;base64,'

const IMG_BOTTOM =
  'data:image/png;base64,'

interface SplashScreenProps {
  onComplete: () => void
}

const SPLASH_CSS = `
  :root { --green:#7ec13f; --bg:#08090a; --d:4.6s; }

  .nexo-splash{
    position:fixed; inset:0; z-index:9999;
    display:grid; place-items:center; overflow:hidden;
    background:
      radial-gradient(ellipse at 50% 46%, rgba(126,193,63,.06) 0%, transparent 55%),
      var(--bg);
    opacity:1; transition:opacity .55s ease;
  }
  .nexo-splash.done{ opacity:0; pointer-events:none; }

  .nexo-stage{
    position:absolute; left:50%; top:50%;
    width:1920px; height:1080px;
    transform:translate(-50%,-50%) scale(1);
    transform-origin:center;
  }

  .nexo-net{
    position:absolute; inset:0;
    transform-origin:960px 470px;
    animation:netLife var(--d) cubic-bezier(.7,0,.3,1) forwards;
  }
  .nexo-net-line{
    position:absolute; left:960px; top:470px; height:1.4px;
    background:var(--green); transform-origin:0 50%;
    transform:translateY(-50%) rotate(var(--ang));
    width:0; animation:draw .55s cubic-bezier(.16,1,.3,1) forwards;
  }
  .nexo-net-node{
    position:absolute; width:9px; height:9px; background:var(--green);
    transform:translate(-50%,-50%) rotate(45deg) scale(0);
    animation:pop .5s cubic-bezier(.34,1.56,.64,1) forwards;
  }

  .nexo-group{
    position:absolute; left:700px; top:210px; width:520px; height:520px;
    transform-origin:center;
    animation:groupMove var(--d) cubic-bezier(.65,0,.35,1) forwards;
  }
  .nexo-half{ position:absolute; inset:0; }
  .nexo-half img{ width:100%; height:100%; display:block; }
  .nexo-half.top{
    clip-path:polygon(0 0,100% 0,100% 100%);
    transform:translate(120px,-120px); opacity:0;
    animation:halfTop var(--d) cubic-bezier(.16,1,.3,1) forwards;
  }
  .nexo-half.bottom{
    clip-path:polygon(0 0,0 100%,100% 100%);
    transform:translate(-120px,120px); opacity:0;
    animation:halfBottom var(--d) cubic-bezier(.16,1,.3,1) forwards;
  }
  .nexo-nexus{
    position:absolute; left:50%; top:50%; width:96px; height:96px;
    margin:-48px 0 0 -48px; background:#fff; opacity:0;
    animation:nexus var(--d) ease-out forwards;
  }

  .nexo-pulse{
    position:absolute; left:960px; top:470px; width:160px; height:160px;
    border:1px solid var(--green);
    transform:translate(-50%,-50%) rotate(45deg) scale(.35); opacity:0;
    animation:pulse var(--d) cubic-bezier(.2,.7,.3,1) forwards;
  }

  .nexo-wordmark{
    position:absolute; left:260px; top:232px; width:1400px; height:615px;
    clip-path:inset(0 100% 0 0);
    animation:wordmark var(--d) cubic-bezier(.65,0,.35,1) forwards;
  }
  .nexo-wordmark img{ width:100%; height:100%; display:block; }
  .nexo-wipe-edge{
    position:absolute; top:270px; left:260px; width:2px; height:380px;
    background:var(--green); box-shadow:0 0 10px var(--green);
    opacity:0; animation:wipeEdge var(--d) cubic-bezier(.65,0,.35,1) forwards;
  }

  @keyframes netLife{
    0%{ opacity:0; transform:scale(1.06); }
    8%{ opacity:1; transform:scale(1); }
    17%{ opacity:1; transform:scale(1); }
    29%{ opacity:0; transform:scale(.08); }
    100%{ opacity:0; transform:scale(.08); }
  }
  @keyframes draw{ from{ width:0; } to{ width:var(--len); } }
  @keyframes pop{ to{ transform:translate(-50%,-50%) rotate(45deg) scale(1); } }

  @keyframes groupMove{
    0%,43%   { transform:translate(0,0) scale(1); }
    61%      { transform:translate(462px,-13px) scale(.755); }
    78%      { transform:translate(462px,-13px) scale(.755); }
    96%,100% { transform:translate(0,0) scale(.74); }
  }
  @keyframes halfTop{
    0%,22%   { transform:translate(120px,-120px); opacity:0; }
    27%      { opacity:1; }
    35%      { transform:translate(0,0); opacity:1; }
    100%     { transform:translate(0,0); opacity:1; }
  }
  @keyframes halfBottom{
    0%,25%   { transform:translate(-120px,120px); opacity:0; }
    30%      { opacity:1; }
    38%      { transform:translate(0,0); opacity:1; }
    100%     { transform:translate(0,0); opacity:1; }
  }
  @keyframes nexus{
    0%,34%{ opacity:0; } 35%{ opacity:.95; } 42%{ opacity:0; } 100%{ opacity:0; }
  }
  @keyframes pulse{
    0%,35%{ transform:translate(-50%,-50%) rotate(45deg) scale(.35); opacity:0; }
    37%   { opacity:.55; }
    52%   { transform:translate(-50%,-50%) rotate(45deg) scale(2.4); opacity:0; }
    100%  { opacity:0; }
  }
  @keyframes wordmark{
    0%,43%   { clip-path:inset(0 100% 0 0); opacity:1; }
    61%      { clip-path:inset(0 28.2% 0 0); opacity:1; }
    78%      { clip-path:inset(0 28.2% 0 0); opacity:1; }
    96%,100% { clip-path:inset(0 28.2% 0 0); opacity:0; }
  }
  @keyframes wipeEdge{
    0%,43%{ opacity:0; left:260px; }
    45%   { opacity:.9; }
    61%   { left:1265px; opacity:.9; }
    65%,100%{ opacity:0; left:1265px; }
  }

  @media (prefers-reduced-motion: reduce){
    .nexo-net,.nexo-pulse,.nexo-wipe-edge{ display:none; }
    .nexo-group{ animation:none; transform:translate(0,0) scale(.74); }
    .nexo-half.top,.nexo-half.bottom{ animation:none; transform:none; opacity:1; }
    .nexo-wordmark{ animation:none; opacity:0; }
  }
`

export function SplashScreen({ onComplete }: SplashScreenProps) {
  useEffect(() => {
    const splash = document.getElementById('nexo-splash-overlay')
    const stage = document.getElementById('nexo-splash-stage')
    if (!splash || !stage) return

    const prefersReduced = window.matchMedia('(prefers-reduced-motion: reduce)').matches

    function fit() {
      if (!stage) return
      const s = Math.min(window.innerWidth / 1920, window.innerHeight / 1080)
      stage.style.transform = `translate(-50%,-50%) scale(${s})`
    }
    fit()
    window.addEventListener('resize', fit)

    if (prefersReduced) {
      const t = setTimeout(onComplete, 800)
      return () => {
        clearTimeout(t)
        window.removeEventListener('resize', fit)
      }
    }

    const safetyTimer = setTimeout(onComplete, 5500)

    const handleTransitionEnd = (e: TransitionEvent) => {
      if (e.propertyName === 'opacity' && splash.classList.contains('done')) {
        splash.style.display = 'none'
        document.dispatchEvent(new CustomEvent('nexo-splash-complete'))
      }
    }
    splash.addEventListener('transitionend', handleTransitionEnd)

    const handleComplete = () => {
      clearTimeout(safetyTimer)
      onComplete()
    }
    document.addEventListener('nexo-splash-complete', handleComplete)

    const animTimer = setTimeout(() => {
      splash.classList.add('done')
    }, 4600)

    return () => {
      clearTimeout(animTimer)
      clearTimeout(safetyTimer)
      window.removeEventListener('resize', fit)
      splash.removeEventListener('transitionend', handleTransitionEnd as EventListener)
      document.removeEventListener('nexo-splash-complete', handleComplete)
    }
  }, [onComplete])

  return (
    <>
      <style dangerouslySetInnerHTML={{ __html: SPLASH_CSS }} />
      <div className="nexo-splash" id="nexo-splash-overlay">
        <div className="nexo-stage" id="nexo-splash-stage">

          <div className="nexo-net">
            <div className="nexo-net-line" style={{ '--len': '492px', '--ang': '-153.4deg', animationDelay: '.05s' } as React.CSSProperties} />
            <div className="nexo-net-line" style={{ '--len': '220px', '--ang': '-149.9deg', animationDelay: '.12s' } as React.CSSProperties} />
            <div className="nexo-net-line" style={{ '--len': '499px', '--ang': '-28.1deg',  animationDelay: '.18s' } as React.CSSProperties} />
            <div className="nexo-net-line" style={{ '--len': '261px', '--ang': '36.4deg',   animationDelay: '.26s' } as React.CSSProperties} />
            <div className="nexo-net-line" style={{ '--len': '576px', '--ang': '13.6deg',   animationDelay: '.32s' } as React.CSSProperties} />
            <div className="nexo-net-line" style={{ '--len': '561px', '--ang': '154.1deg',  animationDelay: '.38s' } as React.CSSProperties} />
            <div className="nexo-net-node" style={{ left: '520px',  top: '250px', animationDelay: '.10s' }} />
            <div className="nexo-net-node" style={{ left: '770px',  top: '360px', animationDelay: '.16s' }} />
            <div className="nexo-net-node" style={{ left: '1400px', top: '235px', animationDelay: '.22s' }} />
            <div className="nexo-net-node" style={{ left: '1170px', top: '625px', animationDelay: '.30s' }} />
            <div className="nexo-net-node" style={{ left: '1520px', top: '605px', animationDelay: '.36s' }} />
            <div className="nexo-net-node" style={{ left: '455px',  top: '715px', animationDelay: '.42s' }} />
          </div>

          <div className="nexo-pulse" />

          <div className="nexo-wordmark">
            <img src={IMG_WORDMARK} alt="NEXO College" />
          </div>
          <div className="nexo-wipe-edge" />

          <div className="nexo-group">
            <div className="nexo-half top"><img src={IMG_TOP} alt="" /></div>
            <div className="nexo-half bottom"><img src={IMG_BOTTOM} alt="" /></div>
            <div className="nexo-nexus" />
          </div>

        </div>
      </div>
    </>
  )
}
